@use "@acorex/styles/index.scss" as *;
@use "@acorex/styles/themes/default.scss" as *;
@use "@acorex/styles/icons/fontawesome/index.scss" as *;

@tailwind base;
@tailwind components;
@tailwind utilities;

import {
  AX_TRANSLATION_CONFIG,
  AX_TRANSLATION_LOADER,
  translationConfig,
} from "@acorex/core/translation";
import { AppTranslationLoader } from "./app.loaders";

export const appConfig: ApplicationConfig = {
  providers: [
    {
      provide: AX_TRANSLATION_LOADER,
      useClass: AppTranslationLoader,
    },
    {
      provide: AX_TRANSLATION_CONFIG,
      useValue: translationConfig({
        preload: {
          langs: ["en-US"],
          scopes: ["acorex"],
        },
        defaults: {
          lang: "en-US",
          scope: "acorex",
        },
      }),
    },
  ],
};

import { AXTranslation, AXTranslationLoader, AXTranslationLoaderOptions } from '@acorex/core/translation';
import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { first, Observable } from 'rxjs';

@Injectable()
export class AppTranslationLoader implements AXTranslationLoader {
  private http = inject(HttpClient);

  load(options: AXTranslationLoaderOptions): Observable<AXTranslation> {
    // The i18n folder is located in the public project folder.
    const httpRequest = this.http.get<AXTranslation>(`/i18n/${options.lang}/${options.scope}.json`).pipe(first());
    return httpRequest;
  }
}

import { AXConversationModule } from '@acorex/components/conversation';
import { AXDialogModule } from '@acorex/components/dialog';
import { AXMediaViewerModule } from '@acorex/components/media-viewer';
import { AXToastModule } from '@acorex/components/toast';
import { AX_DATETIME_HOLIDAYS_LOADER } from '@acorex/core/date-time';
import { AXFormatModule } from '@acorex/core/format';
import { AX_LOCALE_CONFIG } from '@acorex/core/locale';
import { AXLocalStorageService, AX_LOCALSTORAGE_SECRET_KEY } from '@acorex/core/storage';
import { AX_TRANSLATION_CONFIG, AX_TRANSLATION_LOADER, translationConfig } from '@acorex/core/translation';
import { AXValidationModule } from '@acorex/core/validation';
import { OverlayModule } from '@angular/cdk/overlay';
import { provideHttpClient } from '@angular/common/http';
import { ApplicationConfig, importProvidersFrom, provideZoneChangeDetection } from '@angular/core';
import { provideAnimations } from '@angular/platform-browser/animations';
import { provideRouter } from '@angular/router';
import { AppCustomHolidaysLoader, AppTranslationLoader } from './app.loaders';
import { appRoutes } from './app.routes';

export const appConfig: ApplicationConfig = {
  providers: [
    provideHttpClient(),
    provideAnimations(),
    provideZoneChangeDetection({ eventCoalescing: true }),
    provideRouter(appRoutes),
    importProvidersFrom(
      AXValidationModule.forRoot(),
      AXConversationModule.forRoot(),
      AXMediaViewerModule.forRoot(),
      AXFormatModule.forRoot(),
      OverlayModule,
      AXDialogModule,
      AXToastModule,
    ),
    {
      provide: AX_DATETIME_HOLIDAYS_LOADER,
      useClass: AppCustomHolidaysLoader,
    },
    {
      provide: AX_TRANSLATION_LOADER,
      useClass: AppTranslationLoader,
    },
    {
      provide: AX_LOCALE_CONFIG,
      useValue: {
        default: 'en-US',
      },
    },
    {
      provide: AX_TRANSLATION_CONFIG,
      useValue: translationConfig({
        preload: {
          langs: ['en-US'],
          scopes: ['acorex'],
        },
        defaults: {
          lang: 'en-US',
          scope: 'acorex',
        },
      }),
    },
    {
      provide: AXLocalStorageService,
    },
    {
      provide: AX_LOCALSTORAGE_SECRET_KEY,
      useValue: 'secretkey',
    },
  ],
};

import { AXHolidayDate, AXHolidaysLoader, AXHolidaysLoaderOptions } from '@acorex/core/date-time';
import { AXTranslation, AXTranslationLoader, AXTranslationLoaderOptions } from '@acorex/core/translation';
import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { first, Observable } from 'rxjs';

@Injectable()
export class AppCustomHolidaysLoader implements AXHolidaysLoader {
  getHolidays(options?: AXHolidaysLoaderOptions): Promise<AXHolidayDate[]> {
    return new Promise((resolve) => {
      setTimeout(() => {
        resolve([
          {
            date: new Date(2023, 8, 10),
            title: 'Test 1',
          },
          {
            date: new Date(2023, 8, 20),
            title: 'Test 2',
          },
          {
            date: new Date(2025, 3, 9),
            title: 'ACoreX world day',
          },
        ]);
      }, 500);
    });
  }
}

@Injectable()
export class AppTranslationLoader implements AXTranslationLoader {
  private http = inject(HttpClient);
  load(options: AXTranslationLoaderOptions): Observable<AXTranslation> {
    const httpRequest = this.http.get<AXTranslation>(`/i18n/${options.lang}/${options.scope}.json`).pipe(first());
    return httpRequest;
  }
}
